 3→import type { SDUIComponentProps, SDUIContext } from '../models';
 4→
 5→interface PointsInputProps extends SDUIComponentProps {
 6→  label: string;
 7→  placeholder?: string;
 8→  keyboardType?: string;
 9→  textRight?: string;
10→  textError?: string;
11→  mb?: string;
12→  contextKey?: string;
13→}
14→
15→export default function PointsInputAdapter({
16→  props,
17→}: {
18→  props: PointsInputProps;
19→  context: SDUIContext;
20→}) {
21→  const {
22→    label,
23→    placeholder = '0',
24→    keyboardType = 'number-pad',
25→    textRight,
26→    textError,
27→    mb,
28→  } = props;
29→
30→  const [value, setValue] = useState('');
31→  const [error, setError] = useState(false);
32→
33→  const handleChange = useCallback((text: string) => {
34→    setValue(text);
35→    setError(false);
36→  }, []);
37→
38→  const handleUseAll = useCallback(() => {
39→    // In a real implementation, this would read from context/store
40→  }, []);
41→
42→  return (
43→    <InputBox
44→      label={String(label)}
45→      placeholder={String(placeholder)}
46→      showLabel
47→      keyboardType={keyboardType}
48→      value={value}
49→      onChangeText={handleChange}
50→      error={error}
51→      textError={textError ? String(textError) : undefined}
52→      textRight={textRight ? String(textRight) : undefined}
53→      onPressTextRight={textRight ? handleUseAll : undefined}
54→      mb={mb}
55→    />
56→  );
57→}
